#import "YellowPageViewController.h"
#import "DetailViewController.h"
#import "ContactEditViewController.h"
#import "contactsTableView.h"
#import "contactModel.h"
#import <Contacts/Contacts.h>
#import <UIKit/UIKit.h>

@interface YellowPageViewController ()

@property(strong, nonatomic) UIView *backView;
@property(strong, nonatomic) UILabel *labelView;
@property(strong, nonatomic) UIButton *importButton;
@property(strong, nonatomic) contactsTableView *tableView;

@property (nonatomic, strong) NSArray<NSDictionary *> *contacts;



@end

NSString *const ContactAuthorizationChangedNotification = @"ContactAuthorizationChangedNotification";

@implementation YellowPageViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setUpUI];
    [self checkContactPermission];


    UIImage *addImage = [[[UIImage imageNamed:@"A_MainPage_add_icon"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    self.navigationItem.rightBarButtonItem = [[UIBarButtonItem alloc] initWithImage:addImage style:UIBarButtonItemStylePlain target:self action:@selector(gotoEdit)];

    // 注册通讯录变更通知
    [[NSNotificationCenter defaultCenter] addObserver:self
                                             selector:@selector(handleContactStoreChanged)
                                                 name:CNContactStoreDidChangeNotification
                                               object:nil];

    // 注册应用返回前台通知
    [[NSNotificationCenter defaultCenter] addObserver:self
                                             selector:@selector(checkContactPermission)
                                                 name:UIApplicationWillEnterForegroundNotification
                                               object:nil];

}

- (void)dealloc {
    // 移除通知监听
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}


#pragma mark - 监听事件
- (void)handleContactStoreChanged {
    [self checkContactPermission];
}

- (void)checkContactPermission {
    CNAuthorizationStatus status = [CNContactStore authorizationStatusForEntityType:CNEntityTypeContacts];
    dispatch_async(dispatch_get_main_queue(), ^{
        if (status == CNAuthorizationStatusAuthorized) {
            [self handleAuthorizedState];
        } else {
            [self handleUnauthorizedState];
        }
    });
}

- (void)handleAuthorizedState {
    // 更新UI状态
//    self.backView.hidden = YES;
    self.importButton.hidden = YES;
    self.tableView.hidden = NO;

    // 发送全局通知
    [[NSNotificationCenter defaultCenter] postNotificationName:@"kAddressBookAuthorizedNotification" object:nil];

    // 刷新数据
    [self.tableView reloadData];
}

- (void)handleUnauthorizedState {
//    self.backView.hidden = NO;
    self.importButton.hidden = NO;
    self.tableView.hidden = YES;
}


#pragma mark - 点击事件
- (void)requestContactsAccess {
    CNAuthorizationStatus status = [CNContactStore authorizationStatusForEntityType:CNEntityTypeContacts];

    if (status == CNAuthorizationStatusNotDetermined) {
        CNContactStore *store = [[CNContactStore alloc] init];
        [store requestAccessForEntityType:CNEntityTypeContacts completionHandler:^(BOOL granted, NSError *error) {
            if (granted) {
                // 权限获取成功，发送通知触发UI更新
                [[NSNotificationCenter defaultCenter] postNotificationName:ContactAuthorizationChangedNotification object:nil];
            }
        }];
    } else if (status == CNAuthorizationStatusAuthorized) {
        [self handleAuthorizedState];
    } else {
        [self showCustomPermissionAlert];
    }
}

- (void)showCustomPermissionAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"需要通讯录权限"
                                                                   message:@"请允许访问通讯录以获取信息\n(设置->隐私->通讯录中开启)"
                                                            preferredStyle:UIAlertControllerStyleAlert];

    // 跳转系统设置
    UIAlertAction *settingsAction = [UIAlertAction actionWithTitle:@"去设置" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        [[UIApplication sharedApplication] openURL:[NSURL URLWithString:UIApplicationOpenSettingsURLString]
                                           options:@{}
                                 completionHandler:^(BOOL success) {
            if (success) {
                NSLog(@"成功跳转到设置页面");
            } else {
                NSLog(@"跳转失败");
            }
        }];
    }];

    [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:nil]];
    [alert addAction:settingsAction];
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)gotoEdit {
    [self.view endEditing:YES];
    ContactEditViewController *contactsVc = [[ContactEditViewController alloc] init];
    contactsVc.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:contactsVc animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];
}


#pragma mark - firstview的ui

- (void)showDetailWithContact:(contactModel *)contact Name:(NSString *)name with:(NSIndexPath *)indexPath {
    [self.view endEditing:YES];
    DetailViewController *dVC = [[DetailViewController alloc] initWithName:name andContact:contact selectedIndexPath:indexPath];
    [self presentViewController:dVC animated:YES completion:^{
        [SVProgressHUD dismiss];
    }];

}

#pragma mark - setter

- (void)setContacts:(NSMutableArray<contactModel *> *)contacts {
    self.tableView.contacts = contacts;
}
- (NSMutableArray<contactModel *> *)contacts {
    return self.tableView.contacts;
}

#pragma mark - SetUpUI

- (void)setUpUI{

    [self addAllSubviews];
    [self addAllConstraints];
    [self setEvents];

}

- (void)addAllSubviews{

    [self.view addSubview:self.backView];
    [self.view addSubview:self.labelView];
    [self.view addSubview:self.importButton];
    [self.view addSubview:self.tableView];

}

- (void)addAllConstraints{

    [_backView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOM(308));
        make.left.equalTo(self.view).offset(ZOOM(16));
        make.width.mas_equalTo(ZOOM(273));
        make.height.mas_equalTo(ZOOM(60));
    }];
    [_labelView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.backView);
        make.left.equalTo(self.backView).offset(ZOOM(16));
    }];
    [_importButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.backView);
        make.left.equalTo(self.view).offset(ZOOM(16));
        make.width.mas_equalTo(ZOOM(343));
        make.height.mas_equalTo(ZOOM(60));
    }];
    [_tableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOM(-32));
        make.bottom.equalTo(self.view);
        make.left.right.equalTo(self.view).inset(ZOOM(16));
    }];

}

- (void)setEvents{
    [self.importButton addTarget:self action:@selector(requestContactsAccess) forControlEvents:UIControlEventTouchUpInside];

    // 添加权限变更监听
        [[NSNotificationCenter defaultCenter] addObserver:self
                                                 selector:@selector(checkContactPermission)
                                                     name:ContactAuthorizationChangedNotification
                                                   object:nil];

}

#pragma mark - 懒加载

- (UIView *)backView {
    if(_backView == nil){
        _backView = [[UIView alloc] init];
        _backView.backgroundColor = RGBA(230, 231, 235, 1);
        _backView.layer.cornerRadius = ZOOM(12);
        _backView.hidden = YES;
    }
    return _backView;
}

- (UILabel *)labelView{
    if(_labelView == nil){
        _labelView = [UILabel labelWithText:@"Import local contacts" fontSize:18 bold:YES textColor:BLACK_COLOR];
        _labelView.hidden = YES;
    }
    return _labelView;
}

- (UIButton *)importButton{
    if(_importButton == nil){
        _importButton = [[UIButton alloc] init];
        _importButton.layer.cornerRadius = ZOOM(27);
        _importButton.layer.borderWidth = 2;
        _importButton.layer.borderColor = RGB(103, 148, 255).CGColor;
        _importButton.backgroundColor = CLEAR_COLOR;
        [_importButton setTitle:@"Import local contacts" forState:UIControlStateNormal];
        [_importButton setTitleColor:RGB(103, 148, 255) forState:UIControlStateNormal];
    }
    return _importButton;
}

- (contactsTableView *)tableView {
    if (_tableView == nil) {
        CNAuthorizationStatus status = [CNContactStore authorizationStatusForEntityType:CNEntityTypeContacts];
        if(status == CNAuthorizationStatusAuthorized){
            _tableView = [[contactsTableView alloc] initWithAuth:YES];
        }else{
            _tableView = [[contactsTableView alloc] initWithAuth:NO];
        }

        _tableView.backgroundColor = CLEAR_COLOR;
        _tableView.hidden = YES;
    }
    return _tableView;
}

@end

