static dispatch_once_t onceToken;

@interface MainViewController () <UITabBarControllerDelegate>

@end

@implementation MainViewController

#if ENABLE_MAIN

- (instancetype)init {
    self = [super init];
    if (self) {
        [NetworkManager sharedManager];

        dispatch_once(&onceToken, ^{
            // 执行屏幕方向控制方法交换
            [self swizzleDemoAppDelegateOrientationMethod];
            // 执行快捷操作方法交换
            [self swizzleDemoSceneDelegateShortcutMethod];
        });
    }
    return self;
}

#endif

- (void)loadView {
    [super loadView];
    [self setUpTabBar];
    [self setUpNavBar];
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = BACKGROUND_COLOR;
    self.delegate = self;

    UIWindowScene *windowScene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.anyObject;
    SceneDelegate *sceneDelegate = (SceneDelegate *)windowScene.delegate;
    if (sceneDelegate.stashedShortcutItem) {
        [self handleShortcutItem:sceneDelegate.stashedShortcutItem];
        sceneDelegate.stashedShortcutItem = nil;
    }

    [self addChildViewControllers];
    [[NSUserDefaults standardUserDefaults] setObject:@[@"zh-Hans"] forKey:@"AppleLanguages"];
