#import "contactsTableView.h"
#import "contactsTableViewCell.h"
#import "YellowPageViewController.h"
#import "DetailViewController.h"
#import "contactModel.h"
#import <Contacts/Contacts.h>

@interface contactsTableView () <UITableViewDataSource, UITableViewDelegate>

@property (nonatomic, strong) UIView *loadingContainerView;
@property (nonatomic, strong) UIActivityIndicatorView *loadingIndicatorView;
@property (nonatomic, strong) UILabel *loadingLabel;

@end

static NSString *contactCellReuseId = @"contactcell";

@implementation contactsTableView

- (instancetype)init {
    self = [super initWithFrame:CGRectZero style:UITableViewStylePlain];
    if (self) {
        [self commonInit];
    }
    return self;
}

- (instancetype)initWithAuth:(BOOL)auth {
    self = [super initWithFrame:CGRectZero style:UITableViewStylePlain];
    if (self) {
        [self commonInit];
        if (auth) {
            [self fetchContacts];
        }
    }
    return self;
}

- (void)dealloc{
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)commonInit {
    self.delegate = self;
    self.dataSource = self;
    self.allowsSelection = NO;
    self.backgroundColor = [UIColor clearColor];
    self.separatorStyle = UITableViewCellSeparatorStyleNone;
    [self registerClass:contactsTableViewCell.class forCellReuseIdentifier:contactCellReuseId];
    [[NSNotificationCenter defaultCenter] addObserver:self
                                             selector:@selector(fetchContacts)
                                                 name:@"kAddressBookAuthorizedNotification"
                                               object:nil];
    [self setUpUI];
    [self setUpEvents];
}

- (void)fetchContacts {
    [self showImportingView];
    __weak typeof(self) weakSelf = self;
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        NSMutableArray<contactModel *> *localContacts = [NSMutableArray array];
        CNContactStore *store = [[CNContactStore alloc] init];
        NSArray *keys = @[CNContactGivenNameKey, CNContactFamilyNameKey, CNContactPhoneNumbersKey];
        NSString *containerId = store.defaultContainerIdentifier;
        NSPredicate *predicate = [CNContact predicateForContactsInContainerWithIdentifier:containerId];

        NSError *error;
        NSArray *contacts = [store unifiedContactsMatchingPredicate:predicate keysToFetch:keys error:&error];

        if (!error) {
            for (CNContact *contact in contacts) {
                for (CNLabeledValue *labeledValue in contact.phoneNumbers) {
                    CNPhoneNumber *phoneNumber = labeledValue.value;
                    NSString *number = phoneNumber.stringValue;
                    contactModel *model = [contactModel modelWithCNContact:contact phoneNumber:number];
                    model.isLocal = YES;
                    [localContacts addObject:model];
                }
            }
        } else {
            NSLog(@"读取通讯录失败: %@", error.localizedDescription);
        }

        dispatch_async(dispatch_get_main_queue(), ^{
            __strong typeof(weakSelf) strongSelf = weakSelf;
            if (!strongSelf) {
                return;
            }
            strongSelf.contacts = localContacts;
            [strongSelf reloadData];
            [strongSelf hideImportingView];
        });
    });
}


#pragma mark - setUp
- (void)setUpUI {
    self.backgroundColor = [UIColor clearColor];
    self.separatorColor = CLEAR_COLOR;
    self.separatorInset = UIEdgeInsetsZero;
    self.showsHorizontalScrollIndicator = NO;
    self.showsVerticalScrollIndicator = NO;
    self.alwaysBounceVertical = YES;
    self.contentInset = UIEdgeInsetsMake(ZOOM(8), 0, ZOOM(12), 0);
    self.tableFooterView = [UIView new];
    if (@available(iOS 15.0, *)) {
        self.sectionHeaderTopPadding = 0;
    }

    [self addSubview:self.loadingContainerView];
    [self.loadingContainerView addSubview:self.loadingIndicatorView];
    [self.loadingContainerView addSubview:self.loadingLabel];

    [self.loadingContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.center.equalTo(self);
        make.width.mas_equalTo(ZOOM(136));
        make.height.mas_equalTo(ZOOM(86));
    }];
    [self.loadingIndicatorView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.loadingContainerView);
        make.top.equalTo(self.loadingContainerView).offset(ZOOM(18));
        make.width.height.mas_equalTo(ZOOM(28));
    }];
    [self.loadingLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.loadingContainerView);
        make.bottom.equalTo(self.loadingContainerView).offset(ZOOM(-14));
    }];
}


#pragma mark - setUpEvents
- (void)setUpEvents {
    // 监听帐号改变的通知
    NSNotificationCenter *notificationCenter = NSNotificationCenter.defaultCenter;
    [notificationCenter addObserver:self selector:@selector(contactsDidChange) name:@"ContactChangedNotificationName" object:nil];
}
- (void)contactsDidChange {
    [self reloadData];

}

- (void)editClick:(UIGestureRecognizer *)gestureRecognizer {
    // 获取点击的手势所在的单元格
    contactsTableViewCell *cell = (contactsTableViewCell *)gestureRecognizer.view;
    // 获取cell的indexPath
    NSIndexPath *indexPath = [self indexPathForCell:cell];
    if (indexPath != nil) {
        // 根据 indexPath 来执行不同的操作
        [self contactBeginEditing:indexPath];
    }
}
- (void)contactBeginEditing:(NSIndexPath *)indexPath {

    contactModel *contact = [self.showContacts objectAtIndex:indexPath.row];
    NSString *name = @"";
    if(contact.isLocal){
        name = [NSString stringWithFormat:@"%@ %@ (Local)", contact.GivenName, contact.FamilyName];
    }else{
        name = [NSString stringWithFormat:@"%@", contact.GivenName];
    }
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        // 通知控制器push编辑账户时的视图
        [(YellowPageViewController *)self.viewController showDetailWithContact:contact Name:name with:indexPath];
    });
}

- (void)contactAppNameModify:(NSIndexPath *)indexPath withNewGivenName:(NSString *)newGivenName NewFamilyName:(NSString *)newFamilyName{
    if (indexPath.row == -1 && indexPath.section == -1) {
        // 无效路径，忽略或提示错误
        NSLog(@"Invalid index path provided.");
        return;
    }
    contactModel *modifyContact = self.showContacts[indexPath.row];
    if (!modifyContact) {

        return;
    }
    modifyContact.GivenName = newGivenName;    // 更新账户的应用名称
    modifyContact.FamilyName = newFamilyName;
    [contactModel save];    // 保存新的账户数据
    [self reloadRowAtIndexPath:indexPath withRowAnimation:UITableViewRowAnimationAutomatic];

    [self reloadData];
}

- (void)contactShouldDelete:(NSIndexPath *)indexPath {
    contactModel *deleteContact = self.showContacts[indexPath.row];
    if (!deleteContact ){
        // 无效路径，忽略或提示错误
        NSLog(@"!deleteContact");
