- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self loadAlarms];
}

- (void)handleTap:(UIButton *)sender {
    if (self.isEditingMode) {
        // 编辑模式下，根据当前标题执行全选或取消全选
        if ([self.navigationItem.rightBarButtonItem.title isEqualToString:@"全选"]) {
            [self selectAllItems];
        } else if ([self.navigationItem.rightBarButtonItem.title isEqualToString:@"取消全选"]) {
            [self deselectAllItems];
        }
//        self.navigationItem.rightBarButtonItem.title = @"保存";
    } else {
        // 非编辑模式下，显示/隐藏编辑按钮
        self.editButton.hidden = !self.editButton.hidden;
    }
}

- (void)hiddenButton {
    self.editButton.hidden = YES;
}

- (void)selectAllItems {
    // 选择所有项目
    for (NSInteger i = 0; i < self.alarms.count; i++) {
        NSIndexPath *indexPath = [NSIndexPath indexPathForItem:i inSection:0];
        [self.selectedIndexPaths addObject:indexPath];
    }

    // 更新UI
    [self.collectionView reloadData];
    self.navigationItem.rightBarButtonItem.title = @"取消全选";
    self.titleLabel.text = @"已全选";
    self.deleteButton.enabled = YES;
    self.deleteLabel.textColor = RGBA(255, 45, 45, 1);
}

- (void)deselectAllItems {
    // 取消选择所有项目
    [self.selectedIndexPaths removeAllObjects];

    // 更新UI
    [self.collectionView reloadData];
    self.navigationItem.rightBarButtonItem.title = @"全选";
    self.titleLabel.text = @"选择项目";
    self.deleteButton.enabled = NO;
    self.deleteLabel.textColor = RGBA(153, 153, 153, 0.50);
}

- (void)handleEdit:(UIButton *)sender {
    if (self.isEditingMode) {
//        [self handleTap:sender];
        [self exit:sender];
    } else {
        self.isEditingMode = !self.isEditingMode;
        [self handleDelete:sender];
    }
}

- (void)handleDelete:(UIButton *)sender {
    [_edit setImage:nil];
//    [_edit setTitle:@"全选"];
    [_edit setTitle:@"保存"];
    _edit.tintColor = RGBA(74, 80, 219, 1);
    _add.hidden = YES;

    _returnItem.hidden = NO;
    _delete.hidden = NO;

    // 显示底部删除按钮
//    [self showBottomDeleteView];

    // 更新标题
    self.titleLabel.text = @"选择项目";
    self.editButton.hidden = YES;

    // 刷新collectionView显示选择状态
    [self.collectionView reloadData];
//    self.addButton.hidden = self.isEditingMode;
}

- (void)exit:(UIButton *)sender {
    self.isEditingMode = !self.isEditingMode;
    UIImage *editImage = [[[UIImage imageNamed:@"A_edit"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    [_edit setImage:editImage];
    _returnItem.hidden = YES;
    _delete.hidden = YES;
    _add.hidden = NO;

    [self hideBottomDeleteView];
    self.titleLabel.text = @"闹钟";
    [self.selectedIndexPaths removeAllObjects];
    [self.collectionView reloadData];
//    self.addButton.hidden = self.isEditingMode;
}

- (void)showBottomDeleteView {
    self.deleteView.hidden = NO;
}

- (void)hideBottomDeleteView {
    self.deleteView.hidden = YES;
}

- (void)deleteAlarms:(UIButton *)sender {
    NSMutableArray *indexes = [NSMutableArray array];
    for (NSIndexPath *index in _selectedIndexPaths) {
//        [self deleteAlarmAtIndex:index];
        [AlarmModel deleteAlarm:self.alarms[index.item].alarmId];
        [indexes addObject:index];
    }
    for (NSIndexPath *index in indexes) {
        [self.selectedIndexPaths removeObject:index];
    }
    if (self.selectedIndexPaths.count == 0) {
        self.deleteButton.enabled = NO;
        self.deleteLabel.textColor = RGBA(153, 153, 153, 0.50);
    } else {
        self.deleteButton.enabled = YES;
        self.deleteLabel.textColor = RGBA(255, 45, 45, 1);
    }
    [self.navigationItem.rightBarButtonItem setTitle:@"全选"];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"AlarmDataUpdated" object:nil];
}

- (void)popAlert {
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"是否关闭"
                                                                   message:@"关闭后将停止提醒"
                                                            preferredStyle:UIAlertControllerStyleAlert];

    [alert addAction:[UIAlertAction actionWithTitle:@"取消"
                                              style:UIAlertActionStyleDefault
                                            handler:^(UIAlertAction * _Nonnull action) {
        return;
    }]];

    [alert addAction:[UIAlertAction actionWithTitle:@"关闭"
                                              style:UIAlertActionStyleDestructive
                                            handler:^(UIAlertAction * _Nonnull action) {
        [[AlarmManager sharedManager] stopAlarmSound];
        return;
    }]];
    [self presentViewController:alert animated:YES completion:nil];
}
#pragma mark - Data Management
- (void)loadAlarms {
    self.alarms = [[AlarmModel allAlarms] mutableCopy];
    [self updateUIState];
}

