#pragma mark - 手势处理
- (void)handleTap:(UITapGestureRecognizer *)gesture {
    // 获取点击位置
    CGPoint location = [gesture locationInView:self];

    // 检查是否点击在输入框之外
    BOOL isOutsideTitleField = !CGRectContainsPoint(self.nameTextField.frame, location);
//    BOOL isOutsideTextView = !CGRectContainsPoint(self.contentTextView.frame, location);

    if (isOutsideTitleField) {
        // 点击在输入框之外的空白区域，关闭键盘
        [self endEditing:YES];
    }
}


