- (void)addArrowIcons {
    // 铃声区域箭头
    UIImageView *ringtoneArrow = [[UIImageView alloc] initWithImage:[self createArrowImage]];
    ringtoneArrow.contentMode = UIViewContentModeScaleAspectFit;
    [self.ringtoneSection addSubview:ringtoneArrow];

    [ringtoneArrow mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.ringtoneSection);
        make.right.equalTo(self.ringtoneSection).offset(ZOOM(-16));
        make.width.height.mas_equalTo(ZOOM(16));
    }];

    // 提醒区域箭头
    UIImageView *reminderArrow = [[UIImageView alloc] initWithImage:[self createArrowImage]];
    reminderArrow.contentMode = UIViewContentModeScaleAspectFit;
    [self.reminderSection addSubview:reminderArrow];

    [reminderArrow mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.reminderSection);
        make.right.equalTo(self.reminderSection).offset(ZOOM(-16));
        make.width.height.mas_equalTo(ZOOM(16));
    }];
}

- (UIImage *)createArrowImage {
    // 创建简单的箭头图标
    UIGraphicsBeginImageContextWithOptions(CGSizeMake(16, 16), NO, 0.0);
    CGContextRef context = UIGraphicsGetCurrentContext();

    CGContextSetStrokeColorWithColor(context, [UIColor grayColor].CGColor);
    CGContextSetLineWidth(context, 1.5);
    CGContextSetLineCap(context, kCGLineCapRound);

    // 绘制箭头
    CGContextMoveToPoint(context, 4, 4);
    CGContextAddLineToPoint(context, 12, 8);
    CGContextAddLineToPoint(context, 4, 12);

    CGContextStrokePath(context);

    UIImage *arrowImage = UIGraphicsGetImageFromCurrentImageContext();
    UIGraphicsEndImageContext();

    return arrowImage;
}

