#import "AlarmRepeatSettingView.h"

@interface AlarmRepeatSettingView ()

@property (strong, nonatomic) UIView *daysContainerView;

@end

@implementation AlarmRepeatSettingView

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        self.selectedDayIndexes = [NSMutableSet setWithObjects:@2, @3, @4, @5, @6, nil]; // 默认选择周一到周五
        self.dayShortNames = @[@"日", @"一", @"二", @"三", @"四", @"五", @"六"];
        [self setupUI];
    }
    return self;
}

- (void)setupUI {
    self.backgroundColor = RGBA(243, 243, 243, 1);

    [self addSubview:self.containerView];

    [self.containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self);
    }];

    // 重复日期区域
    [self.containerView addSubview:self.repeatSection];
    [self.repeatSection mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.containerView);
        make.height.mas_equalTo(ZOOM(120));
    }];

    [self.repeatSection addSubview:self.repeatTitleLabel];
    [self.repeatSection addSubview:self.selectedDatesLabel];
    [self.repeatSection addSubview:self.daysContainerView];

    [self.repeatTitleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.repeatSection).offset(ZOOM(16));
        make.left.equalTo(self.repeatSection).offset(ZOOMW(16));
        make.right.equalTo(self.repeatSection).offset(ZOOMW(-16));
    }];

    [self.selectedDatesLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.repeatTitleLabel.mas_bottom).offset(ZOOM(8));
        make.left.equalTo(self.repeatSection).offset(ZOOMW(16));
        make.right.equalTo(self.repeatSection).offset(ZOOMW(-16));
    }];

    [self.daysContainerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.selectedDatesLabel.mas_bottom).offset(ZOOM(16));
        make.left.equalTo(self.repeatSection).offset(ZOOMW(16));
        make.right.equalTo(self.repeatSection).offset(ZOOMW(-19));
        make.height.mas_equalTo(ZOOM(40));
    }];

    // 设置星期按钮
    [self setupDayButtons];

    // 分隔线
    [self.containerView addSubview:self.separatorLine];
    [self.separatorLine mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.repeatSection.mas_bottom);
        make.left.equalTo(self.containerView).offset(ZOOM(16));
        make.right.equalTo(self.containerView);
        make.height.mas_equalTo(0.5);
    }];

    // 节假日设置区域
    [self.containerView addSubview:self.holidaySection];
    [self.holidaySection mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.separatorLine.mas_bottom);
        make.left.right.equalTo(self.containerView);
        make.height.mas_equalTo(ZOOM(72));
        make.bottom.equalTo(self.containerView);
    }];

    [self.holidaySection addSubview:self.holidayTitleLabel];
    [self.holidaySection addSubview:self.holidaySubtitleLabel];
    [self.holidaySection addSubview:self.holidaySwitch];

    [self.holidayTitleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.holidaySection).offset(ZOOM(16));
        make.left.equalTo(self.holidaySection).offset(ZOOM(16));
        make.right.equalTo(self.holidaySwitch.mas_left).offset(ZOOM(-8));
    }];

    [self.holidaySubtitleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.holidayTitleLabel.mas_bottom).offset(ZOOM(4));
        make.left.equalTo(self.holidaySection).offset(ZOOM(16));
        make.right.equalTo(self.holidaySwitch.mas_left).offset(ZOOM(-8));
    }];

    [self.holidaySwitch mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.holidaySection);
        make.right.equalTo(self.holidaySection).offset(ZOOM(-16));
    }];

    // 更新显示
    [self updateSelectedDatesDisplay];
}

- (void)setupDayButtons {
    NSMutableArray *buttons = [NSMutableArray array];
    UIView *previousView = nil;

    for (int i = 0; i < 7; i++) {
        UIButton *button = [UIButton buttonWithType:UIButtonTypeCustom];
        button.tag = i + 1;
        [button setTitle:self.dayShortNames[i] forState:UIControlStateNormal];
        button.titleLabel.font = KEEPASS_FONT(14);
        button.layer.cornerRadius = ZOOM(16);
        button.layer.masksToBounds = YES;

        // 设置初始状态
        [self updateDayButtonAppearance:button];

        [button addTarget:self action:@selector(dayButtonTapped:) forControlEvents:UIControlEventTouchUpInside];

        [self.daysContainerView addSubview:button];
        [buttons addObject:button];

        [button mas_makeConstraints:^(MASConstraintMaker *make) {
            make.centerY.equalTo(self.daysContainerView);
            make.width.height.mas_equalTo(ZOOMW(32));

            if (previousView) {
                make.left.equalTo(previousView.mas_right).offset(ZOOMW(14));
            } else {
                make.left.equalTo(self.daysContainerView);
            }

            if (i == 6) {
                make.right.equalTo(self.daysContainerView);
            }
        }];

        previousView = button;
    }

    self.dayButtons = [buttons copy];
}

- (void)updateDayButtonAppearance:(UIButton *)button {
    NSLog(@"%@", self.selectedDayIndexes)
    NSLog(@"%@", @(button.tag))
    BOOL isSelected = [self.selectedDayIndexes containsObject:@(button.tag)];

    if (isSelected) {
        button.backgroundColor = RGBA(29, 182, 255, 1);
        [button setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];
    } else {
        button.backgroundColor = RGBA(230, 230, 230, 1);
        [button setTitleColor:BLACK_COLOR forState:UIControlStateNormal];
    }
}

- (void)updateSelectedDatesDisplay {
    if (self.selectedDayIndexes.count == 0) {
        self.selectedDatesLabel.text = @"响一次";
    } else if (self.selectedDayIndexes.count == 7) {
        self.selectedDatesLabel.text = @"每天";
    } else if (self.selectedDayIndexes.count == 2 &&
               [self.selectedDayIndexes containsObject:@1] &&
               [self.selectedDayIndexes containsObject:@7]) {
        self.selectedDatesLabel.text = @"周末";
    } else if (self.selectedDayIndexes.count == 5 &&
               ![self.selectedDayIndexes containsObject:@7] &&
               ![self.selectedDayIndexes containsObject:@1]) {
        self.selectedDatesLabel.text = @"工作日";
    } else {
        // 显示具体选中的日期
        NSArray *sortedIndexes = [[self.selectedDayIndexes allObjects] sortedArrayUsingSelector:@selector(compare:)];
        NSMutableArray *dayNames = [NSMutableArray array];

        for (NSNumber *index in sortedIndexes) {
            [dayNames addObject:self.dayShortNames[index.integerValue - 1]];
        }

        self.selectedDatesLabel.text = [dayNames componentsJoinedByString:@", "];
    }
}

#pragma mark - Actions

- (void)dayButtonTapped:(UIButton *)sender {
    NSNumber *dayIndex = @(sender.tag);

    if ([self.selectedDayIndexes containsObject:dayIndex]) {
        [self.selectedDayIndexes removeObject:dayIndex];
    } else {
        [self.selectedDayIndexes addObject:dayIndex];
    }

    [self updateDayButtonAppearance:sender];
    [self updateSelectedDatesDisplay];

    if (self.onRepeatSettingChange) {
        self.onRepeatSettingChange();
    }
}

- (void)holidaySwitchChanged:(UISwitch *)sender {
    if (self.onRepeatSettingChange) {
        self.onRepeatSettingChange();
    }
}

- (void)updateViewSelectionState {
    // 遍历所有日期按钮
    for (UIButton *dayButton in self.dayButtons) {
        // 更新每个按钮的显示状态
        [self updateDayButtonAppearance:dayButton];
    }

    // 可选：更新底部显示选中日期的标签文本
    [self updateSelectedDatesDisplay];
}

