- (instancetype)initWithAlarm:(AlarmModel *)alarm {
    self = [super init];
    if (self) {
        self.Alarm = alarm;
        self.view.backgroundColor = WHITE_COLOR;
        self.isNewAlarm = NO;
        self.headerView.titleLabel.text = self.Alarm.name;
        self.timePicker.date = self.Alarm.selectedTime;
        self.settingView.nameTextField.text = self.Alarm.name;
        self.settingView.ringtoneValueLabel.text = self.Alarm.ringtoneName;
