    vc.modalPresentationStyle = UIModalPresentationFullScreen;
    vc.settingsBlock = ^(BOOL remindEnabled, NSString *interval, NSString *frequency) {
        NSLog(@"设置变更:");
        NSLog(@"提醒开关: %@", remindEnabled ? @"开" : @"关");
        NSLog(@"提醒间隔: %@", interval);
        NSLog(@"提醒次数: %@", frequency);
