    UIButton *button = [[UIButton alloc] init];
    [button setTitle:title forState:UIControlStateNormal];
    [button setTitleColor:[UIColor blackColor] forState:UIControlStateNormal];
    [button setTitleColor:[UIColor whiteColor] forState:UIControlStateSelected]; // 选中状态文字颜色
    button.layer.cornerRadius = ZOOM(24);
    button.backgroundColor = WHITE_COLOR;
    button.tag = tag;
    button.titleLabel.font = [UIFont systemFontOfSize:16 weight:UIFontWeightMedium];
    [button addTarget:self action:@selector(buttonTapped:) forControlEvents:UIControlEventTouchUpInside];
    return button;
}

- (void)buttonTapped:(UIButton *)sender {
     if (sender == self.currentSelectedButton) {
         return;
     }

    self.currentSelectedButton.selected = NO;
    self.currentSelectedButton.backgroundColor = WHITE_COLOR;

    sender.selected = YES;
    sender.backgroundColor = RGBA(29, 182, 255, 1);
    self.isCustomize = sender.tag;

    self.currentSelectedButton = sender;
    [self updateUI];
    NSLog(@"当前选中的按钮Tag: %ld", (long)sender.tag);
}

@end

