#import "ReminderLaterViewController.h"
#import "SelectorPopupView.h"
#import "ShowHeaderView.h"

@interface ReminderLaterViewController ()

@property (nonatomic, strong) ShowHeaderView *headerView;

@property (nonatomic, strong) UIScrollView *scrollView;
@property (nonatomic, strong) UIView *contentView;

@property (nonatomic, strong) UIView *topEnableView;
@property (nonatomic, strong) UILabel *enableTitleLabel;
@property (nonatomic, strong) UISwitch *enableSwitch;

@property (nonatomic, strong) UIView *reminderSettingView;

@property (nonatomic, strong) UIButton *intervalButton;
@property (nonatomic, strong) UILabel *intervalValueLabel;
@property (nonatomic, strong) UIImageView *interImage;

@property (nonatomic, strong) UIButton *frequencyButton;
@property (nonatomic, strong) UILabel *frequencyValueLabel;
@property (nonatomic, strong) UIImageView *frequencyImage;

@property (nonatomic, assign) BOOL remindEnabled;

@property (nonatomic, strong) MASConstraint *contentBottomConstraint;

@end

@implementation ReminderLaterViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = BACKGROUND_COLOR;
    self.remindEnabled = YES;

    [self setupUI];
    [self updateSettingState];
    [_headerView showAppearAnimation];
}

- (void)viewWillDisappear:(BOOL)animated {
    [super viewWillDisappear:animated];

    // 页面即将消失时传递数据
    if (self.settingsBlock) {
        NSString *interval = self.intervalValueLabel.text ?: @"5分钟";
        NSString *frequency = self.frequencyValueLabel.text ?: @"3次";

        self.settingsBlock(self.remindEnabled, interval, frequency);
    }
}

#pragma mark - UI
- (void)setupUI {

    [self.view addSubview:self.headerView];
    [self.view addSubview:self.scrollView];
    [self.scrollView addSubview:self.contentView];

    // 顶部
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(86));
    }];

    // scroll
    [_scrollView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.view);
        make.top.equalTo(self.headerView.mas_bottom);
    }];

    // content
    [_contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.scrollView);
        make.width.equalTo(self.scrollView);
    }];

    // 顶部开启按钮
    [self.contentView addSubview:self.topEnableView];
    [self.topEnableView addSubview:self.enableTitleLabel];
    [self.topEnableView addSubview:self.enableSwitch];

    [_topEnableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(20));
        make.left.right.equalTo(self.contentView).inset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(54));
    }];

    [_enableTitleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.topEnableView).offset(ZOOM(20));
        make.centerY.equalTo(self.topEnableView);
    }];

    [_enableSwitch mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.topEnableView).offset(ZOOM(-20));
        make.centerY.equalTo(self.topEnableView);
    }];

    // 下方设置区域
    [self.contentView addSubview:self.reminderSettingView];

    [_reminderSettingView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topEnableView.mas_bottom).offset(ZOOM(16));
        make.left.right.equalTo(self.contentView).inset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(112));
    }];

    // 间隔
    [self.reminderSettingView addSubview:self.intervalButton];
    [self.reminderSettingView addSubview:self.intervalValueLabel];
    [self.reminderSettingView addSubview:self.interImage];

    [_intervalButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.reminderSettingView);
        make.height.mas_equalTo(ZOOM(56));
    }];

    [_intervalValueLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.intervalButton).offset(ZOOM(-45));
        make.centerY.equalTo(self.intervalButton);
    }];

    [_interImage mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.intervalButton).offset(ZOOM(-16));
        make.centerY.equalTo(self.intervalButton);
        make.height.width.mas_equalTo(ZOOM(24));
    }];

    // 次数
    [self.reminderSettingView addSubview:self.frequencyButton];
    [self.reminderSettingView addSubview:self.frequencyValueLabel];
    [self.reminderSettingView addSubview:self.frequencyImage];

    [_frequencyButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.reminderSettingView);
        make.top.equalTo(self.intervalButton.mas_bottom).offset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(56));
    }];

    [_frequencyValueLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.frequencyButton).offset(ZOOM(-45));
        make.centerY.equalTo(self.frequencyButton);
    }];

    [_frequencyImage mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.frequencyButton).offset(ZOOM(-16));
        make.centerY.equalTo(self.frequencyButton);
        make.height.width.mas_equalTo(ZOOM(24));
    }];

    // content bottom 处理
    [self.contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        self.contentBottomConstraint = make.bottom.equalTo(self.reminderSettingView.mas_bottom).offset(40);
    }];
}

#pragma mark - 交互

/// Switch 开关
- (void)enableSwitchChanged:(UISwitch *)sender {
    self.remindEnabled = sender.isOn;
    [self updateSettingState];
}

/// 根据开关改变可点击状态 + UI
- (void)updateSettingState {

    self.intervalButton.userInteractionEnabled = self.remindEnabled;
    self.frequencyButton.userInteractionEnabled = self.remindEnabled;

    CGFloat alpha = self.remindEnabled ? 1.0 : 0.4;
    self.reminderSettingView.alpha = alpha;
}

/// 点击“提醒间隔”
- (void)intervalButtonTapped {
    NSArray *items = @[@"5分钟", @"10分钟", @"15分钟", @"20分钟", @"25分钟", @"30分钟"];

    SelectorPopupView *popup = [[SelectorPopupView alloc] initWithItems:items];
    popup.selectCallback = ^(NSString *title, NSInteger index) {
        self.intervalValueLabel.text = title;
    };
    [popup showFromView:self.intervalButton inView:self.view];
}

/// 点击“提醒次数”
- (void)frequencyButtonTapped {
    NSArray *items = @[@"1次", @"2次", @"3次", @"4次", @"5次"];

    SelectorPopupView *popup = [[SelectorPopupView alloc] initWithItems:items];
    popup.selectCallback = ^(NSString *title, NSInteger index) {
        self.frequencyValueLabel.text = title;
    };
    [popup showFromView:self.frequencyButton inView:self.view];
}

#pragma mark - Lazy

- (ShowHeaderView *)headerView {
    if (!_headerView) {
        _headerView = [[ShowHeaderView alloc] init];
        _headerView.titleLabel.text = @"稍后提醒";
    }
    return _headerView;
}

- (UIScrollView *)scrollView {
    if (!_scrollView) {
        _scrollView = [[UIScrollView alloc] init];
    }
    return _scrollView;
}

- (UIView *)contentView {
    if (!_contentView) {
        _contentView = [[UIView alloc] init];
    }
    return _contentView;
}

- (UIView *)topEnableView {
    if (!_topEnableView) {
        _topEnableView = [[UIView alloc] init];
        _topEnableView.backgroundColor = WHITE_COLOR;
        _topEnableView.layer.cornerRadius = 14;
    }
    return _topEnableView;
}

- (UILabel *)enableTitleLabel {
    if (!_enableTitleLabel) {
        _enableTitleLabel = [[UILabel alloc] init];
        _enableTitleLabel.text = @"稍后提醒";
        _enableTitleLabel.font = [UIFont systemFontOfSize:17 weight:UIFontWeightMedium];
    }
    return _enableTitleLabel;
}

- (UISwitch *)enableSwitch {
    if (!_enableSwitch) {
        _enableSwitch = [[UISwitch alloc] init];
        _enableSwitch.onTintColor = RGBA(1, 102, 255, 1);
        _enableSwitch.on = YES;
        [_enableSwitch addTarget:self action:@selector(enableSwitchChanged:) forControlEvents:UIControlEventValueChanged];
    }
    return _enableSwitch;
}

- (UIView *)reminderSettingView {
    if (!_reminderSettingView) {
        _reminderSettingView = [[UIView alloc] init];
        _reminderSettingView.backgroundColor = CLEAR_COLOR;
        _reminderSettingView.layer.cornerRadius = 14;
    }
    return _reminderSettingView;
}

- (UIButton *)intervalButton {
    if (!_intervalButton) {
        _intervalButton = [[UIButton alloc] init];
        [_intervalButton setTitle:@"响铃间隔" forState:UIControlStateNormal];
        [_intervalButton setTitleColor:[UIColor blackColor] forState:UIControlStateNormal];
        _intervalButton.titleLabel.font = [UIFont systemFontOfSize:16];
        _intervalButton.contentHorizontalAlignment = UIControlContentHorizontalAlignmentLeft;
        _intervalButton.contentEdgeInsets = UIEdgeInsetsMake(0, 20, 0, 0);
        _intervalButton.backgroundColor = WHITE_COLOR;
        _intervalButton.layer.cornerRadius = 16;
        [_intervalButton addTarget:self action:@selector(intervalButtonTapped) forControlEvents:UIControlEventTouchUpInside];
    }
    return _intervalButton;
}

- (UILabel *)intervalValueLabel {
    if (!_intervalValueLabel) {
        _intervalValueLabel = [[UILabel alloc] init];
        _intervalValueLabel.text = @"5分钟";
        _intervalValueLabel.font = [UIFont systemFontOfSize:15];
        _intervalValueLabel.textColor = [UIColor grayColor];
    }
    return _intervalValueLabel;
}

- (UIButton *)frequencyButton {
    if (!_frequencyButton) {
        _frequencyButton = [[UIButton alloc] init];
        [_frequencyButton setTitle:@"响铃次数" forState:UIControlStateNormal];
        [_frequencyButton setTitleColor:[UIColor blackColor] forState:UIControlStateNormal];
        _frequencyButton.titleLabel.font = [UIFont systemFontOfSize:16];
        _frequencyButton.contentHorizontalAlignment = UIControlContentHorizontalAlignmentLeft;
        _frequencyButton.contentEdgeInsets = UIEdgeInsetsMake(0, 20, 0, 0);
        _frequencyButton.layer.cornerRadius = 16;
        _frequencyButton.backgroundColor = WHITE_COLOR;
        [_frequencyButton addTarget:self action:@selector(frequencyButtonTapped) forControlEvents:UIControlEventTouchUpInside];
    }
    return _frequencyButton;
}

- (UILabel *)frequencyValueLabel {
    if (!_frequencyValueLabel) {
        _frequencyValueLabel = [[UILabel alloc] init];
        _frequencyValueLabel.text = @"3次";
        _frequencyValueLabel.font = [UIFont systemFontOfSize:15];
        _frequencyValueLabel.textColor = [UIColor grayColor];
    }
    return _frequencyValueLabel;
}

- (UIImageView *)createImageView {
    UIImageView *imageView = [[UIImageView alloc] init];
    imageView.image = [UIImage imageNamed:@"A_select"];
    return imageView;
}

- (UIImageView *)interImage {
    if (!_interImage) {
        _interImage = [self createImageView];
    }
    return _interImage;
}

- (UIImageView *)frequencyImage {
    if (!_frequencyImage) {
        _frequencyImage = [self createImageView];
    }
    return _frequencyImage;
}

@end

