    [super viewDidLoad];

    self.view.backgroundColor = WHITE_COLOR;
    self.selectedIndexPaths = [NSMutableSet set];

    UIImage *addImage = [[[UIImage imageNamed:@"A_add"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    UIImage *deleteImage = [[[UIImage imageNamed:@"A_delete"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];

    _add = [[UIBarButtonItem alloc] initWithImage:addImage style:UIBarButtonItemStylePlain target:self action:@selector(addAlarmTapped:)];
    _edit = [[UIBarButtonItem alloc] initWithImage:deleteImage style:UIBarButtonItemStylePlain target:self action:@selector(handleEdit:)];

//    UIImage *returnImage = [[[UIImage imageNamed:@"A_return"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
//    UIImage *deleteImage = [[[UIImage imageNamed:@"A_delete"] imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
