- (void)addAlarmTapped:(UIButton *)sender {
//    [sender showClickedAnimation];

    ClockEditViewController *ceVC = [[ClockEditViewController alloc] init];
    ceVC.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:ceVC animated:YES completion:nil];
}

- (void)switchValueChanged:(UISwitch *)sender {
    NSInteger index = sender.tag;
    if (index >= 0 && index < self.alarms.count) {
        AlarmModel *alarm = self.alarms[index];
        [alarm toggleAlarm];
        [self.collectionView reloadItemsAtIndexPaths:@[[NSIndexPath indexPathForItem:index inSection:0]]];
    }
}

#pragma mark - UICollectionView DataSource & Delegate
- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.alarms.count;
}

- (UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    ClockCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"ClockCell" forIndexPath:indexPath];

    AlarmModel *alarm = self.alarms[indexPath.item];
    BOOL isSelected = [self.selectedIndexPaths containsObject:indexPath];

    [cell configureWithAlarm:alarm isEditing:self.isEditingMode isSelected:isSelected];

    cell.switchControl.tag = indexPath.item;
    [cell.switchControl addTarget:self action:@selector(switchValueChanged:) forControlEvents:UIControlEventValueChanged];

    return cell;
}

