#import "ClockCell.h"

@implementation ClockCell

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        [self setupUI];
        self.backgroundColor = [UIColor clearColor];
    }
    return self;
}

- (void)setupUI {
    [self.contentView addSubview:self.containerView];
    [self.containerView addSubview:self.timeLabel];
    [self.containerView addSubview:self.detailLabel];
    [self.containerView addSubview:self.switchControl];
    [self.containerView addSubview:self.selectionImageView];

    [self.containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.contentView);
    }];

    [self.timeLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.containerView).offset(ZOOM(16));
//        make.centerY.equalTo(self.containerView);
        make.top.bottom.equalTo(self.containerView);
    }];

    [self.detailLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.containerView).offset(ZOOM(16));
        make.top.equalTo(self.timeLabel.mas_bottom).offset(ZOOM(8));
//        make.right.equalTo(self.switchControl.mas_left).offset(ZOOM(-12));
        make.bottom.equalTo(self.containerView).offset(ZOOM(-16));
    }];

    [self.switchControl mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.containerView).offset(ZOOM(-16));
        make.centerY.equalTo(self.containerView);
    }];

    [self.selectionImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.containerView).offset(ZOOM(-16));
        make.centerY.equalTo(self.containerView);
        make.height.width.mas_equalTo(ZOOM(24));
    }];
}

- (void)configureWithAlarm:(AlarmModel *)alarm isEditing:(BOOL)isEditing isSelected:(BOOL)isSelected {
    // 格式化时间显示
    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    formatter.dateFormat = @"HH:mm";
    self.timeLabel.text = [formatter stringFromDate:alarm.selectedTime];
    // 设置详情文本
    self.detailLabel.text = [self detailTextForAlarm:alarm];
    // 设置开关状态
    self.switchControl.on = [alarm isAlarmEnabled];

    // 编辑模式下的UI变化
    self.switchControl.hidden = isEditing;
    self.selectionImageView.hidden = !isEditing;

    if (isEditing) {
        // 显示选择状态
//        NSString *imageName = isSelected ? @"A_checkmark_selected" : @"A_checkmark_unselected";
        NSString *imageName = @"A_delete";
        self.selectionImageView.image = [UIImage imageNamed:imageName];
    }

}

- (NSString *)detailTextForAlarm:(AlarmModel *)alarm {
    NSMutableString *detail = [NSMutableString string];

    // 处理重复日期
    if (alarm.selectedDayIndexes && alarm.selectedDayIndexes.count > 0) {
        if (alarm.selectedDayIndexes.count == 7) {
            [detail appendString:@"每天"];
        } else {
            NSArray *dayNames = @[@"周日", @"周一", @"周二", @"周三", @"周四", @"周五", @"周六"];
            NSArray *shortDayNames = @[@"日", @"一", @"二", @"三", @"四", @"五", @"六"];
            NSMutableArray *selectedDays = [NSMutableArray array];

            // 获取排序后的日期索引
            NSArray *sortedIndexes = [[alarm.selectedDayIndexes allObjects] sortedArrayUsingSelector:@selector(compare:)];

            // 根据数量决定使用全名还是缩写
            NSArray *displayNames = (sortedIndexes.count <= 3) ? dayNames : shortDayNames;

            for (NSNumber *index in sortedIndexes) {
                if (index.integerValue < displayNames.count) {
                    [selectedDays addObject:displayNames[index.integerValue - 1]];
                }
            }
            [detail appendString:[selectedDays componentsJoinedByString:@", "]];
        }

        // 处理节假日跳过
        if (alarm.holidaySkipEnabled && [alarm.holidaySkipEnabled boolValue]) {
            [detail appendString:@", 节假日除外"];
        }

        // 添加闹钟名称（如果有）
        if (alarm.name && alarm.name.length > 0) {
            [detail appendFormat:@" | %@", alarm.name];
        }
    } else {
        [detail appendString:@"响一次"];

        // 单次闹钟的闹钟名称
        if (alarm.name && alarm.name.length > 0) {
            [detail appendFormat:@" | %@", alarm.name];
        }
    }

    return detail;
}

- (void)prepareForReuse {
    [super prepareForReuse];
    self.timeLabel.text = nil;
    self.detailLabel.text = nil;
    [self.switchControl removeTarget:nil action:nil forControlEvents:UIControlEventAllEvents];
}

#pragma mark - Lazy Loading
- (UIView *)containerView {
    if (!_containerView) {
        _containerView = [[UIView alloc] init];
        _containerView.backgroundColor = WHITE_COLOR;
        _containerView.layer.cornerRadius = ZOOM(31);
        _containerView.layer.masksToBounds = YES;
    }
    return _containerView;
}

- (UILabel *)timeLabel {
    if (!_timeLabel) {
        _timeLabel = [[UILabel alloc] init];
        _timeLabel.font = KEEPASS_FONT_WBOLD(24);
        _timeLabel.textColor = BLACK_COLOR;
    }
    return _timeLabel;
}

- (UILabel *)detailLabel {
    if (!_detailLabel) {
        _detailLabel = [[UILabel alloc] init];
        _detailLabel.font = KEEPASS_FONT(14);
        _detailLabel.textColor = [UIColor darkGrayColor];
        _detailLabel.numberOfLines = 2;
        _detailLabel.lineBreakMode = NSLineBreakByTruncatingTail;
        _detailLabel.hidden = YES;
    }
    return _detailLabel;
}

- (UISwitch *)switchControl {
    if (!_switchControl) {
        _switchControl = [[UISwitch alloc] init];
        _switchControl.onTintColor = RGBA(0, 122, 255, 1);
    }
    return _switchControl;
}

- (UIImageView *)selectionImageView {
    if (!_selectionImageView) {
        _selectionImageView = [[UIImageView alloc] init];

    }
    return _selectionImageView;
}

@end

