- (void)timePickerValueChanged:(UIDatePicker *)sender {
    // 创建日期格式器，提取时分
    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    formatter.dateFormat = @"HH:mm"; // 24小时制

    self.selectedTime = sender.date;

    NSString *selectedTimeString = [formatter stringFromDate:self.selectedTime];
    NSLog(@"用户设置的时间为: %@", selectedTimeString);
}

- (void)setupUI {

    [self.view addSubview:self.headerView];
    [self.view addSubview:self.scrollView];
    [self.scrollView addSubview:self.contentView];
    [self.contentView addSubview:self.settingView];
    [self.contentView addSubview:self.timePicker];

    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(88));
    }];
    [_scrollView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.left.right.equalTo(self.view);
        make.top.equalTo(self.headerView.mas_bottom);
    }];
    [_contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.scrollView);
        make.width.equalTo(self.scrollView);
        self.contentBottomConstraint = make.bottom.equalTo(self.timePicker.mas_bottom).offset(ZOOM(20));
    }];

    [_settingView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(10));
        make.left.right.equalTo(self.contentView).inset(ZOOM(8));
        make.height.mas_equalTo(ZOOM(202));
    }];

