- (void)configureWithAlarm:(AlarmModel *)alarm isEditing:(BOOL)isEditing isSelected:(BOOL)isSelected {
    // 格式化时间显示
    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    formatter.dateFormat = @"HH:mm";
    self.timeLabel.text = [formatter stringFromDate:alarm.selectedTime];
    // 设置详情文本
    self.detailLabel.text = [self detailTextForAlarm:alarm];
    // 设置开关状态
    self.switchControl.on = [alarm isAlarmEnabled];

    // 编辑模式下的UI变化
    self.switchControl.hidden = isEditing;
    self.selectionImageView.hidden = !isEditing;

    if (isEditing) {
        // 显示选择状态
//        NSString *imageName = isSelected ? @"A_checkmark_selected" : @"A_checkmark_unselected";
        NSString *imageName = @"A_delete";
        self.selectionImageView.image = [UIImage imageNamed:imageName];
    }

}

- (NSString *)detailTextForAlarm:(AlarmModel *)alarm {
    NSMutableString *detail = [NSMutableString string];

    // 处理重复日期
    if (alarm.selectedDayIndexes && alarm.selectedDayIndexes.count > 0) {
        if (alarm.selectedDayIndexes.count == 7) {
            [detail appendString:@"每天"];
        } else {
            NSArray *dayNames = @[@"周日", @"周一", @"周二", @"周三", @"周四", @"周五", @"周六"];
            NSArray *shortDayNames = @[@"日", @"一", @"二", @"三", @"四", @"五", @"六"];
            NSMutableArray *selectedDays = [NSMutableArray array];

            // 获取排序后的日期索引
            NSArray *sortedIndexes = [[alarm.selectedDayIndexes allObjects] sortedArrayUsingSelector:@selector(compare:)];

            // 根据数量决定使用全名还是缩写
            NSArray *displayNames = (sortedIndexes.count <= 3) ? dayNames : shortDayNames;

            for (NSNumber *index in sortedIndexes) {
                if (index.integerValue < displayNames.count) {
                    [selectedDays addObject:displayNames[index.integerValue - 1]];
                }
            }
            [detail appendString:[selectedDays componentsJoinedByString:@", "]];
        }

        // 处理节假日跳过
        if (alarm.holidaySkipEnabled && [alarm.holidaySkipEnabled boolValue]) {
            [detail appendString:@", 节假日除外"];
        }

        // 添加闹钟名称（如果有）
        if (alarm.name && alarm.name.length > 0) {
            [detail appendFormat:@" | %@", alarm.name];
        }
    } else {
        [detail appendString:@"响一次"];

        // 单次闹钟的闹钟名称
        if (alarm.name && alarm.name.length > 0) {
            [detail appendFormat:@" | %@", alarm.name];
        }
    }

    return detail;
}

