    self.titleLabel.font = KEEPASS_FONT(16);
    self.titleLabel.textColor = RGB(90, 90, 90);
    [self.containerView addSubview:self.titleLabel];

    self.versionLabel = [[UILabel alloc] init];
    self.versionLabel.text = @"1.0";
    self.versionLabel.font = KEEPASS_FONT(16);
    self.versionLabel.textColor = RGBA(153, 153, 153, 1);
    [self.containerView addSubview:self.versionLabel];

    [self setupConstraints];
}

- (void)setupConstraints {
    [self.containerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.contentView);
    }];

    [self.iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.containerView);
        make.left.equalTo(self.containerView).offset(ZOOMW(14));
        make.width.height.mas_equalTo(ZOOMW(18));
    }];

    [self.goView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.containerView);
        make.right.equalTo(self.containerView).offset(ZOOMW(-16));
        make.height.mas_equalTo(ZOOMW(16));
        make.width.mas_equalTo(ZOOMW(16));
    }];

    [self.versionLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.containerView);
        make.right.equalTo(self.containerView).offset(ZOOMW(-16));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.containerView);
        make.left.equalTo(self.iconImageView.mas_right).offset(ZOOMW(12));
        make.right.lessThanOrEqualTo(self.versionLabel.mas_left).offset(ZOOMW(-12));
    }];
}

- (void)configureWithTitle:(NSString *)title
                  iconType:(MyCellIconType)iconType
                showsArrow:(BOOL)showsArrow
               versionText:(NSString *)versionText {
    self.titleLabel.text = title;
    self.goView.hidden = !showsArrow;
    self.versionLabel.hidden = versionText.length == 0;
    self.versionLabel.text = versionText;
    self.iconImageView.image = [self iconImageForType:iconType];
}

- (UIImage *)iconImageForType:(MyCellIconType)iconType {
    CGSize size = CGSizeMake(18, 18);
    UIGraphicsBeginImageContextWithOptions(size, NO, 0);
    CGContextRef context = UIGraphicsGetCurrentContext();
    UIColor *strokeColor = RGB(150, 150, 150);
    CGContextSetStrokeColorWithColor(context, strokeColor.CGColor);
    CGContextSetLineWidth(context, 1.4);
    CGContextSetLineCap(context, kCGLineCapRound);
    CGContextSetLineJoin(context, kCGLineJoinRound);

    switch (iconType) {
        case MyCellIconTypeFeedback:
            CGContextStrokeEllipseInRect(context, CGRectMake(2.5, 2.5, 10, 10));
            CGContextMoveToPoint(context, 10, 11);
            CGContextAddLineToPoint(context, 14.5, 15);
            CGContextMoveToPoint(context, 5, 6);
            CGContextAddLineToPoint(context, 10, 6);
            CGContextMoveToPoint(context, 5, 9);
            CGContextAddLineToPoint(context, 8.5, 9);
            break;
        case MyCellIconTypeSetting:
            CGContextStrokeEllipseInRect(context, CGRectMake(5, 5, 8, 8));
            CGContextMoveToPoint(context, 9, 2);
            CGContextAddLineToPoint(context, 9, 4);
            CGContextMoveToPoint(context, 9, 14);
            CGContextAddLineToPoint(context, 9, 16);
            CGContextMoveToPoint(context, 2, 9);
            CGContextAddLineToPoint(context, 4, 9);
            CGContextMoveToPoint(context, 14, 9);
            CGContextAddLineToPoint(context, 16, 9);
            CGContextMoveToPoint(context, 4.2, 4.2);
            CGContextAddLineToPoint(context, 5.5, 5.5);
            CGContextMoveToPoint(context, 12.5, 12.5);
            CGContextAddLineToPoint(context, 13.8, 13.8);
            CGContextMoveToPoint(context, 12.5, 5.5);
            CGContextAddLineToPoint(context, 13.8, 4.2);
            CGContextMoveToPoint(context, 4.2, 13.8);
            CGContextAddLineToPoint(context, 5.5, 12.5);
            break;
        case MyCellIconTypeSupport:
            CGContextStrokeEllipseInRect(context, CGRectMake(2.5, 4.5, 13, 11));
            CGContextMoveToPoint(context, 5.5, 11);
            CGContextAddLineToPoint(context, 12.5, 11);
            CGContextMoveToPoint(context, 9, 3);
            CGContextAddLineToPoint(context, 9, 6);
            break;
        case MyCellIconTypeVersion:
            CGContextStrokeEllipseInRect(context, CGRectMake(3, 3, 12, 12));
            CGContextMoveToPoint(context, 9, 7);
            CGContextAddLineToPoint(context, 9, 12);
            CGContextMoveToPoint(context, 9, 5);
            CGContextAddLineToPoint(context, 9, 5.2);
            break;
    }

    CGContextStrokePath(context);
    UIImage *image = UIGraphicsGetImageFromCurrentImageContext();
    UIGraphicsEndImageContext();
    return image;
}

@end

