- (void)deleteAlarms:(UIButton *)sender {
    if (self.selectedIndexPaths.count == 0) {
        return;
    }

    NSArray<NSIndexPath *> *indexes = [[self.selectedIndexPaths allObjects] sortedArrayUsingComparator:^NSComparisonResult(NSIndexPath *obj1, NSIndexPath *obj2) {
        if (obj1.item > obj2.item) {
            return NSOrderedAscending;
        }
        if (obj1.item < obj2.item) {
            return NSOrderedDescending;
        }
        return NSOrderedSame;
    }];
    for (NSIndexPath *indexPath in indexes) {
        if (indexPath.item < self.alarms.count) {
            [AlarmModel deleteAlarm:self.alarms[indexPath.item].alarmId];
        }
    }
    [self.selectedIndexPaths removeAllObjects];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"AlarmDataUpdated" object:nil];
}

