- (void)buttonTapped:(UIButton *)sender {
     if (sender == self.currentSelectedButton) {
         return;
     }

    self.currentSelectedButton.selected = NO;
    self.currentSelectedButton.backgroundColor = WHITE_COLOR;

    sender.selected = YES;
    sender.backgroundColor = RGBA(29, 182, 255, 1);
    self.isCustomize = sender.tag;

    self.currentSelectedButton = sender;
    [self updateUI];
    NSLog(@"当前选中的按钮Tag: %ld", (long)sender.tag);
}

