@implementation ContactEditViewController

- (instancetype)initWithContact:(contactModel *)contact andSelectedIndexPath:(NSIndexPath *)selectedIndexPath{
    self = [super init];
    if (self) {
        self.Contact = contact;
        if(contact.isLocal){
            self.Name.text = [NSString stringWithFormat:@"%@ %@ (Local)", contact.GivenName, contact.FamilyName];
        }else{
            self.Name.text = [NSString stringWithFormat:@"%@", contact.GivenName];
        }
        self.Num.text = contact.phoneNum;
        self.selectedIndexPath = selectedIndexPath;
        self.view.backgroundColor = BACKGROUND_COLOR;
        if(!self.Contact.isLocal){
            self.headerView.editButton.hidden = NO;
        }
    }
    return self;
}

- (void)viewDidLoad {

    [super viewDidLoad];
    if(_Contact){
        self.headerView.titleLabel.text = @"Edit";
    }else{
        self.headerView.titleLabel.text = @"Add contact";
    }
    self.view.backgroundColor = BACKGROUND_COLOR;
    [self setUpUI];
    [_headerView showAppearAnimation];
    [self TypeJudgement];

}

- (void)TypeJudgement{
    if(_Contact){
        if(!_Contact.isLocal){
            _headerView.editButton.hidden = NO;
        }else{
            _headerView.editButton.hidden = YES;
        }
    }
}

- (void)numDidCopied:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];

    NSString *content = _Num.text;
    if (content == nil || content.isEmpty) {
        [UIView showHUDWithStatus:NSLocalizedString(@"It's empty", nil) imageName:nil];
        return;
    }

    UIPasteboard *pastepoard = [UIPasteboard generalPasteboard];
    pastepoard.string = _Num.text;

    [UIView showHUDWithStatus:NSLocalizedString(@"Copy successfully", nil) imageName:@"Success"];

}
- (void)emailDidCopied:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];

    NSString *content = _Email.text;
    if (content == nil || content.isEmpty) {
        [UIView showHUDWithStatus:NSLocalizedString(@"It's empty", nil) imageName:nil];
        return;
    }

    UIPasteboard *pastepoard = [UIPasteboard generalPasteboard];
    pastepoard.string = _Email.text;

    [UIView showHUDWithStatus:NSLocalizedString(@"Copy successfully", nil) imageName:@"Success"];

}

- (void)save:(UIButton *)sender {

    NSString *trimmedName = [_Name.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedNum = [_Num.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedEmail = [_Email.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedNotes = [_Notes.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    if (trimmedName.length == 0 && trimmedNum.length == 0 && trimmedEmail.length == 0 && trimmedNotes.length == 0) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Invalid Input"
                                                                       message:@"At least one field must be filled"
                                                                preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"OK" style:UIAlertActionStyleDefault handler:nil]];
        [self presentViewController:alert animated:YES completion:nil];
        return;
    }

    if(!_Contact){
        contactModel *ContacttoEdit = [[contactModel alloc] init];
        ContacttoEdit.GivenName = _Name.text;
        ContacttoEdit.phoneNum = _Num.text;
        ContacttoEdit.email = _Email.text;
        ContacttoEdit.notes = _Notes.text;
        [contactModel.contacts addObject:ContacttoEdit];
    }else{
        NSUInteger indexToUpdate = [contactModel.contacts indexOfObject:_Contact];
        _Contact.GivenName = _Name.text;
        _Contact.phoneNum = _Num.text;
        _Contact.email = _Email.text;
        _Contact.notes = _Notes.text;
        [contactModel.contacts replaceObjectAtIndex:indexToUpdate withObject:_Contact];
    }

    [contactModel save];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"ContactChangedNotificationName" object:nil];
    //连续两次返回
    DetailViewController *vc2 = (DetailViewController *)self.presentingViewController;
    [self dismissViewControllerAnimated:NO completion:^{
        // 再关闭 VC2（此时已回到 VC2）
        [vc2 dismissViewControllerAnimated:YES completion:nil];
    }];
}

- (void)delete:(UIButton *)sender{

    dispatch_async(dispatch_get_main_queue(), ^{
        contactModel *deletecontact = self.Contact;

        [contactModel.contacts removeObject:deletecontact];
        [contactModel save];


        [[NSNotificationCenter defaultCenter] postNotificationName:@"ContactChangedNotificationName" object:nil];
    });
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [SVProgressHUD dismiss];
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [UIView showHUDWithStatus:NSLocalizedString(@"Delete Successful", nil) imageName:@"Success"];
            DetailViewController *vc2 = (DetailViewController *)self.presentingViewController;
            [self dismissViewControllerAnimated:NO completion:^{
                [vc2 dismissViewControllerAnimated:YES completion:nil];
            }];
        });
    });
}

