+- (NSString *)resolvedDisplayName {
+    NSString *name = [self.displayName stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
+    if (name.length > 0) {
+        return name;
+    }
+    
+    NSMutableArray<NSString *> *parts = [NSMutableArray array];
+    if (self.Contact.GivenName.length > 0) {
+        [parts addObject:self.Contact.GivenName];
+    }
+    if (self.Contact.FamilyName.length > 0) {
+        [parts addObject:self.Contact.FamilyName];
+    }
+    name = [parts componentsJoinedByString:@" "];
+    return name.length > 0 ? name : @"Contact";
+}
