    NSString *trimmedText = [text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    BOOL hasContent = trimmedText.length > 0;
    label.text = hasContent ? trimmedText : placeholder;
    label.textColor = hasContent ? RGB(75, 75, 75) : RGBA(200, 200, 200, 1);
}

