- (void)save:(UIButton *)sender {
    NSString *trimmedName = [self.nameTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedNum = [self.numTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedEmail = [self.emailTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    NSString *trimmedNotes = [self.noteTextField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    if (trimmedName.length == 0 && trimmedNum.length == 0 && trimmedEmail.length == 0 && trimmedNotes.length == 0) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Invalid Input"
                                                                       message:@"At least one field must be filled"
                                                                preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"OK" style:UIAlertActionStyleDefault handler:nil]];
        [self presentViewController:alert animated:YES completion:nil];
        return;
    }

    if (!self.Contact) {
        contactModel *newContact = [[contactModel alloc] init];
        newContact.GivenName = trimmedName;
        newContact.phoneNum = trimmedNum;
        newContact.email = trimmedEmail;
        newContact.notes = trimmedNotes;
        [contactModel.contacts addObject:newContact];
    } else {
        self.Contact.GivenName = trimmedName;
        self.Contact.phoneNum = trimmedNum;
        self.Contact.email = trimmedEmail;
        self.Contact.notes = trimmedNotes;

        NSUInteger indexToUpdate = [contactModel.contacts indexOfObject:self.Contact];
        if (indexToUpdate != NSNotFound) {
            [contactModel.contacts replaceObjectAtIndex:indexToUpdate withObject:self.Contact];
        }
    }

    [contactModel save];
    [[NSNotificationCenter defaultCenter] postNotificationName:@"ContactChangedNotificationName" object:nil];
    [self closePageAfterSave];
}

